Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and MSTest v3+ timeout/cancellation patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // MSTest v3+ injects CancellationToken via TestContext for timeout support
    public TestContext TestContext { get; set; } = null!;

    [TestMethod]
    [Timeout(5000)] // milliseconds — fails test if exceeded
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        // Arrange
        var handler = new MockHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass the MSTest-managed cancellation token
        var result = await fetcher.FetchAsync(
            "https://example.com/data",
            TestContext.CancellationTokenSource.Token);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ThrowsHttpRequestException_OnFailure()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com/fail",
                TestContext.CancellationTokenSource.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOperationCanceled_WhenTokenCancelled()
    {
        // Arrange — a handler that delays, simulating slow network
        var handler = new MockHttpMessageHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    // Reusable mock handler (no external mocking library needed)
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key modern MSTest patterns shown:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `GetAwaiter().GetResult()` needed |
| `[Timeout(ms)]` | MSTest cancels the test via `CancellationTokenSource` if it exceeds the limit |
| `TestContext.CancellationTokenSource.Token` | MSTest v3+ provides a token wired to the timeout — pass it through to your SUT |
| `Assert.ThrowsExceptionAsync<T>` | Async-aware exception assertion |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over response and cancellation behavior |

The `[Timeout]` + `TestContext.CancellationTokenSource.Token` combination ensures that if your code hangs, the test fails deterministically rather than running forever.
